class FakeEmbeddingModel:
    """Provides deterministic vectors for fast tests without model downloads."""

    def encode(self, texts: List[str], **_: Any) -> List[List[float]]:
        """Encodes text into a small handcrafted feature space."""
        vectors: List[List[float]] = []
        for text in texts:
            text_lower = text.lower()
            vectors.append(
                [
                    1.0 if "database" in text_lower else 0.0,
                    1.0 if "timeout" in text_lower else 0.0,
                    1.0 if "enabled" in text_lower else 0.0,
                    1.0 if "disabled" in text_lower else 0.0,
                    1.0 if "weather" in text_lower else 0.0,
                    float(len(text_lower.split())) / 20.0,
                ]
            )
        return vectors


class FakeContradictionClassifier:
    """Returns a predictable contradiction score for selected phrase pairs."""

    def __call__(self, sequence: str, **_: Any) -> dict[str, Any]:
        """Classifies a statement pair into contradiction-related labels."""
        text = sequence.lower()
        if "enabled" in text and "disabled" in text:
            return {
                "labels": ["contradicts", "entails", "unrelated"],
                "scores": [0.92, 0.06, 0.02],
            }
        return {
            "labels": ["unrelated", "entails", "contradicts"],
            "scores": [0.80, 0.15, 0.05],
        }


