def test_score_relevance_ranks_domain_chunks_higher() -> None:
    """Ensures query-matching chunks receive stronger relevance scores."""
    watchdog = _build_watchdog()
    query = "How do we fix database timeout errors?"
    chunks = [
        "Database timeout can be reduced with indexing.",
        "The weather is sunny in Madrid.",
    ]

    scores = watchdog.score_relevance(query, chunks)

    assert len(scores) == 2
    assert scores[0] > scores[1]


