def test_filter_removes_irrelevant_and_redundant_chunks() -> None:
    """Ensures filter keeps only high-value non-duplicate context chunks."""
    watchdog = _build_watchdog()
    query = "How can I fix a database timeout?"
    chunks = [
        "Database timeout can be reduced with indexing.",
        "Database timeout can be reduced with indexing.",
        "The weather is sunny in Madrid.",
    ]

    filtered, report = watchdog.filter(
        query,
        chunks,
        thresholds={"relevance_min": 0.45, "redundancy_max": 0.85, "conflict_min": 0.70},
    )

    assert len(filtered) == 1
    assert "Database timeout" in filtered[0]
    assert report["summary"]["dropped_chunks"] == 2


def test_langchain_wrapper_filters_documents() -> None:
    """Ensures wrapper returns only documents retained by watchdog filtering."""
    watchdog = _build_watchdog()
    retriever = DummyRetriever(
        documents=[
            DummyDocument("Database timeout can be reduced with indexing."),
            DummyDocument("Database timeout can be reduced with indexing."),
            DummyDocument("The weather is sunny in Madrid."),
        ]
    )

    wrapped = LangChainWatchdogRetriever(
        retriever,
        watchdog=watchdog,
        thresholds={"relevance_min": 0.45, "redundancy_max": 0.85, "conflict_min": 0.70},
    )

    filtered_docs = wrapped.get_relevant_documents("database timeout guidance")

    assert len(filtered_docs) == 1
    assert wrapped.last_report is not None
    assert "Database timeout" in filtered_docs[0].page_content


